import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "What is a required minimum distribution?", a: "A required minimum distribution is the minimum amount that must be withdrawn each year from certain retirement accounts after reaching the required age." },
  { q: "At what age must you take RMDs?", a: "The starting age depends on current IRS rules and your birth year. Many retirees now begin at age 73 or later under recent law changes." },
  { q: "How is RMD calculated?", a: "RMD is generally calculated by dividing the prior year-end account balance by an IRS life expectancy factor." },
  { q: "What happens if you don't take your RMD?", a: "Missing an RMD can trigger IRS penalties, though corrective action may reduce the penalty in some cases." },
  { q: "Do Roth IRAs have RMDs?", a: "Roth IRAs generally do not require lifetime RMDs for the original owner, but inherited Roth accounts may have distribution rules." },
];

const money = (v: number, d = 0) => formatCurrencyValue(Number.isFinite(v) ? v : 0, { maximumFractionDigits: d });
const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";
const factorTable: Record<number, number> = { 72: 27.4, 73: 26.5, 74: 25.5, 75: 24.6, 76: 23.7, 77: 22.9, 78: 22.0, 79: 21.1, 80: 20.2, 81: 19.4, 82: 18.5, 83: 17.7, 84: 16.8, 85: 16.0, 86: 15.2, 87: 14.4, 88: 13.7, 89: 12.9, 90: 12.2 };
const factor = (age: number) => factorTable[Math.round(age)] ?? Math.max(1.9, 27.4 - (age - 72) * 0.85);

export default function RMDCalculator() {
  useCurrencyVersion();
  const [age, setAge] = useState(73);
  const [balance, setBalance] = useState(500000);
  const [accountType, setAccountType] = useState("Traditional IRA");
  const result = useMemo(() => {
    const f = factor(age);
    const rmd = balance / f;
    const rows = Array.from({ length: 10 }, (_, i) => {
      const a = age + i;
      const fac = factor(a);
      const projectedBalance = balance * Math.pow(1.04, i);
      return { age: a, factor: fac, balance: projectedBalance, rmd: projectedBalance / fac };
    });
    return { factor: f, rmd, rows };
  }, [age, balance]);
  const comparison = [72, 73, 75, 78, 80, 85, 90].map((a) => ({ age: a, factor: factor(a), r500: 500000 / factor(a), r1m: 1000000 / factor(a), r2m: 2000000 / factor(a) }));

  return (
    <>
      <SEOHead title="Free RMD Calculator Online - Calculate Required Minimum Distribution Instantly | CalcHive" description="Free online RMD calculator. Calculate your required minimum distribution from any retirement account using IRS life expectancy tables instantly. 100% free, no signup required." canonical="/rmd-calculator" keywords="free RMD calculator, required minimum distribution calculator free online, IRA RMD calculator free, calculate RMD free, 401k RMD calculator free online" category="Financial Calculators" breadcrumbName="Free RMD Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free RMD Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Estimate required minimum distributions using IRS-style life expectancy factors.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 mb-8">
            <div><label className="text-sm font-semibold text-foreground block mb-2">Current age</label><input type="number" value={age} onChange={(e) => setAge(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Retirement account balance</label><input type="number" value={balance} onChange={(e) => setBalance(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Account type</label><select value={accountType} onChange={(e) => setAccountType(e.target.value)} className={inputClass}><option>Traditional IRA</option><option>401k</option><option>Inherited IRA</option></select></div>
          </div>
          <div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Required Minimum Distribution</p><p className="text-5xl sm:text-6xl font-black text-white">{money(result.rmd)}</p></div>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Life expectancy factor</p><p className="text-lg font-extrabold text-foreground">{result.factor.toFixed(1)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Account type</p><p className="text-lg font-extrabold text-foreground">{accountType}</p></div></div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Your Required Minimum Distribution for Free</h2><p className="text-muted-foreground leading-relaxed">Divide the retirement account balance by the IRS life expectancy factor for your age to estimate the required minimum distribution.</p>
          <h2 className="text-2xl font-bold text-foreground">IRS RMD Rules and Life Expectancy Tables Explained</h2>
          <div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Required Minimum Distribution by Age and Account Balance</caption><thead className="bg-muted/60"><tr>{["Age", "IRS Life Expectancy Factor", "RMD on $500K", "RMD on $1M", "RMD on $2M"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{comparison.map((row) => <tr key={row.age}><td className="py-2.5 px-3 font-semibold">{row.age}</td><td className="py-2.5 px-3">{row.factor.toFixed(1)}</td><td className="py-2.5 px-3">{money(row.r500)}</td><td className="py-2.5 px-3">{money(row.r1m)}</td><td className="py-2.5 px-3">{money(row.r2m)}</td></tr>)}</tbody></table></div>
          <h2 className="text-2xl font-bold text-foreground">Free Retirement Account RMD Tool for Everyone</h2>
          <div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">RMD Amounts for Next 10 Years</caption><thead className="bg-muted/60"><tr>{["Age", "Projected Balance", "Life Expectancy Factor", "Estimated RMD"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{result.rows.map((row) => <tr key={row.age}><td className="py-2.5 px-3">{row.age}</td><td className="py-2.5 px-3">{money(row.balance)}</td><td className="py-2.5 px-3">{row.factor.toFixed(1)}</td><td className="py-2.5 px-3">{money(row.rmd)}</td></tr>)}</tbody></table></div>
        </section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/rmd-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


